void triangle() {
    float a, b, c, s, area;
    printf("Enter three sides of triangle: ");
    scanf("%f %f %f", &a, &b, &c);
    if (a + b > c && a + c > b && b + c > a) {
        s = (a + b + c) / 2;
        area = sqrt(s * (s - a) * (s - b) * (s - c));
        printf("Triangle Area: %.2f, Perimeter: %.2f\n", area, a + b + c);
    } else {
        printf("Invalid triangle sides!\n");
    }
}

