    if (f(a) * f(b) >= 0) {
        printf("Bisection method fails. f(a) and f(b) must have opposite signs.\n");
        return;
    }

    printf("\nIter\t a\t\t b\t\t x\t\t f(x)\n");
    do {
        x = (a + b) / 2;
        printf("%d\t %.6lf\t %.6lf\t %.6lf\t %.6lf\n", iter++, a, b, x, f(x));
        if (f(a) * f(x) < 0)
            b = x;
        else
            a = x;
    } while (fabs(f(x)) > tol);

    printf("\nRoot: %.6lf\n", x);
}

void newtonRaphson() {
    double x0, x1, tol;
    int iter = 0;
    printf("Enter initial guess: ");
    scanf("%lf", &x0);
    printf("Enter tolerance: ");
    scanf("%lf", &tol);

    printf("\nIter\t x0\t\t f(x0)\t\t x1\n");
    do {
        if (df(x0) == 0) {
            printf("Derivative is zero. Newton-Raphson fails.\n");
            return;
        }
        x1 = x0 - f(x0) / df(x0);
        printf("%d\t %.6lf\t %.6lf\t %.6lf\n", iter++, x0, f(x0), x1);
        x0 = x1;
    } while (fabs(f(x1)) > tol);

    printf("\nRoot: %.6lf\n", x1);
}

void secant() {
    double x0, x1, x2, tol;
    int iter = 0;
    printf("Enter two initial guesses: ");
    scanf("%lf %lf", &x0, &x1);
    printf("Enter tolerance: ");
    scanf("%lf", &tol);

    printf("\nIter\t x0\t\t x1\t\t x2\t\t f(x2)\n");
    do {
        if (f(x1) - f(x0) == 0) {
            printf("Division by zero. Secant method fails.\n");
            return;
        }
        x2 = x1 - (f(x1) * (x1 - x0)) / (f(x1) - f(x0));
        printf("%d\t %.6lf\t %.6lf\t %.6lf\t %.6lf\n", iter++, x0, x1, x2, f(x2));
        x0 = x1;
        x1 = x2;
    } while (fabs(f(x2)) > tol);

    printf("\nRoot: %.6lf\n", x2);
}

int main() {
    int choice;
    while (1) {
        printf("\n--- Root Finding Methods ---\n");
        printf("1. Bisection Method\n");
        printf("2. Newton-Raphson Method\n");
        printf("3. Secant Method\n");
        printf("4. Exit\n");
        printf("Enter choice: ");
        scanf("%d", &choice);

        switch (choice) {
            case 1: bisection(); break;
            case 2: newtonRaphson(); break;
            case 3: secant(); break;
            case 4: exit(0);
            default: printf("Invalid choice!\n");
        }
    }
    return 0;
}

#include <stdio.h>
#include <math.h>

double f(double x) {
    return x * x * x + 2 * x * x + 3 * x + 5; // Example function: f(x) = x^3 + 2x^2 + 3x + 5
}

int main() {
    double x, h;
    printf("Enter the value of x at which derivative is to be calculated: ");
    scanf("%lf", &x);
    printf("Enter the step size h: ");
    scanf("%lf", &h);

    double forward = (f(x + h) - f(x)) / h;
    double backward = (f(x) - f(x - h)) / h;
    double central = (f(x + h) - f(x - h)) / (2 * h);

    printf("\nNumerical Differentiation Results at x = %.4lf with h = %.4lf:\n", x, h);
    printf("Forward Difference: %.6lf\n", forward);
    printf("Backward Difference: %.6lf\n", backward);
    printf("Central Difference: %.6lf\n", central);

    // Exact derivative for x^3 + 2x^2 + 3x + 5 is 3x^2 + 4x + 3
    double exact = 3 * x * x + 4 * x + 3;
    printf("Exact Derivative:    %.6lf\n", exact);

    return 0;
}

#include <stdio.h>
#include <math.h>

double f(double x) {
    return 1 / (1 + x * x); // Example function: f(x) = 1 / (1 + x^2)
}

int main() {
    double a, b;
    int n;
    printf("Enter lower limit of integration a: ");
    scanf("%lf", &a);
    printf("Enter upper limit of integration b: ");
    scanf("%lf", &b);
    printf("Enter number of sub-intervals n (even for Simpson's 1/3 rule): ");
    scanf("%d", &n);

    double h = (b - a) / n;
    double sum_trap = f(a) + f(b);
    double sum_simp = f(a) + f(b);

    for (int i = 1; i < n; i++) {
        double x = a + i * h;
        sum_trap += 2 * f(x);

        if (i % 2 == 0) {
            sum_simp += 2 * f(x);
        } else {
            sum_simp += 4 * f(x);
        }
    }

    double result_trap = (h / 2) * sum_trap;
    double result_simp = (h / 3) * sum_simp;

    printf("\nNumerical Integration Results:\n");
    printf("Trapezoidal Rule Result: %.6lf\n", result_trap);
    if (n % 2 == 0) {
        printf("Simpson's 1/3 Rule Result: %.6lf\n", result_simp);
    } else {
        printf("Simpson's 1/3 Rule cannot be applied (n is odd).\n");
    }

    return 0;
}

